css:
.loader {color: var(--loader-color, #0284c7);
  --loader-secondary-color: #7dd3fc;
  --loader-bg: #ffffff;
  width: 64px;
  aspect-ratio: 1;
  display: grid;
}.loader:before,.loader:after {content: "";
  grid-area: 1/1;
  border: 8px solid var(--loader-color, #0284c7);
  box-sizing: content-box;
  margin: auto;
  aspect-ratio: 1;
  animation: l8 infinite 1s steps(4,jump-none);
}.loader:before {animation-delay: -.5s;
  border-radius: 50%;
}@keyframes l8 {0% {width: 0% }to {width: 75%}}
